begin;

-- Generated by scripts/generate-rich-seed.mjs
-- Mixed plan:
--   90 days
--   510 aptitude questions
--   26 linked DSA problems
--   26 linked SQL problems
--   52 HR prompts
-- Aptitude bank:
--   100 days
--   1000 aptitude questions
--
-- This file keeps the mixed plan active and stores the 1000-question aptitude bank
-- as a separate inactive plan template for future rotation.

update public.plan_templates
set is_active = false
where is_active = true
  and slug <> 'placement-sprint-rich-v1';


-- Placement Sprint Rich v1
insert into public.plan_templates (name, slug, duration_days, is_active)
values ('Placement Sprint Rich v1', 'placement-sprint-rich-v1', 90, true)
on conflict (slug) do update
set
  name = excluded.name,
  duration_days = excluded.duration_days,
  is_active = excluded.is_active;


