insert into public.tasks (
  plan_day_id,
  task_type,
  title,
  topic,
  instructions_md,
  solution_md,
  estimated_minutes,
  difficulty,
  is_active
)
select
  pd.id,
  seed.task_type,
  seed.title,
  seed.topic,
  seed.instructions_md,
  seed.solution_md,
  seed.estimated_minutes,
  seed.difficulty,
  true
from public.plan_days pd
join public.plan_templates pt on pt.id = pd.plan_template_id
join (
  values
    (1, 'aptitude', 'Percentages and Discounts Drill 1', 'percentages, discounts, marked price', 'Answer all ten questions before checking the explanations.

Write one-line working for each question so you can spot formula mistakes.', 'Review the shortcuts only after attempting the full set.

Mark whether the mistake was concept, arithmetic, or speed related.', 60, 'easy'),
    (2, 'aptitude', 'Ratios and Shares Drill 1', 'ratio, share, direct proportion', 'Reduce the ratio first before doing any other calculation.

Translate every statement into parts and total parts.', 'Most ratio errors come from skipping the total-parts step.

Use a quick table if the question mixes two conditions.', 60, 'easy'),
    (3, 'dsa', 'Arrays and Hashing Pair', 'arrays, hashing', 'Open the easy problem first and solve it without reading editorials.

Then solve the medium problem and record your final approach, complexity, and one tricky edge case.', 'For each problem, write the brute-force idea, optimized idea, time complexity, and space complexity.

If you got stuck, note the exact point of confusion so the next revisit is easier.', 60, 'medium'),
    (4, 'sql', 'Filters and Ranking Pair', 'basic filtering, ranking', 'Solve the easy query first and make sure you understand the table relationship or filter.

Then solve the medium query and note the join, grouping, ranking, or window logic you used.', 'After solving externally, come back and record the clean query pattern in your own words.

If the medium problem uses ranking or grouping, note why that approach is safer than the first idea that came to mind.', 55, 'medium'),
    (5, 'aptitude', 'Speed and Distance Drill 1', 'speed, distance, time, average speed', 'Write the unit before substituting values.

For average speed, decide whether the trip uses equal distances or equal times.', 'Keep km/h to m/s conversions visible in rough work.

For average speed, do not average the numbers blindly.', 60, 'easy'),
    (6, 'hr', 'Tell Me About Yourself Lab', 'self introduction', 'Answer every prompt in your own words before reading the sample guidance.

Keep answers specific, short, and anchored in real experience where possible.', 'Review your answers for structure, evidence, and clarity rather than trying to sound perfect.

If an answer feels weak, rewrite only the opening and closing lines first.', 45, 'easy'),
    (7, 'aptitude', 'Trains and Relative Speed Drill 1', 'trains, poles, platforms, relative speed', 'Convert speed into m/s before touching the train length.

Use total length when a platform is involved.', 'Train questions are mostly unit conversion plus total distance.

Opposite and same-direction movement change the relative speed.', 60, 'easy'),
    (8, 'aptitude', 'Boats and Streams Drill 1', 'boats, streams, upstream, downstream', 'Write downstream and upstream equations explicitly.

Keep the still-water and stream speeds as separate unknowns.', 'Use half-sum for still water and half-difference for stream speed.

After that, distance and time use the same speed-distance formula.', 60, 'easy'),
    (9, 'aptitude', 'Time and Work Drill 1', 'time and work, rates, combined efficiency', 'Convert each worker into one-day work before combining them.

