insert into public.tasks (
  plan_day_id,
  task_type,
  title,
  topic,
  instructions_md,
  solution_md,
  estimated_minutes,
  difficulty,
  is_active
)
select
  pd.id,
  seed.task_type,
  seed.title,
  seed.topic,
  seed.instructions_md,
  seed.solution_md,
  seed.estimated_minutes,
  seed.difficulty,
  true
from public.plan_days pd
join public.plan_templates pt on pt.id = pd.plan_template_id
join (
  values
    (1, 'aptitude', 'Percentages and Discounts Drill 1', 'percentages, discounts, marked price', 'Answer all ten questions before checking the explanations.

Write one-line working for each question so you can spot formula mistakes.', 'Review the shortcuts only after attempting the full set.

Mark whether the mistake was concept, arithmetic, or speed related.', 60, 'easy'),
    (2, 'aptitude', 'Ratios and Shares Drill 1', 'ratio, share, direct proportion', 'Reduce the ratio first before doing any other calculation.

Translate every statement into parts and total parts.', 'Most ratio errors come from skipping the total-parts step.

Use a quick table if the question mixes two conditions.', 60, 'easy'),
    (3, 'aptitude', 'Speed and Distance Drill 1', 'speed, distance, time, average speed', 'Write the unit before substituting values.

For average speed, decide whether the trip uses equal distances or equal times.', 'Keep km/h to m/s conversions visible in rough work.

For average speed, do not average the numbers blindly.', 60, 'easy'),
    (4, 'aptitude', 'Trains and Relative Speed Drill 1', 'trains, poles, platforms, relative speed', 'Convert speed into m/s before touching the train length.

Use total length when a platform is involved.', 'Train questions are mostly unit conversion plus total distance.

Opposite and same-direction movement change the relative speed.', 60, 'easy'),
    (5, 'aptitude', 'Boats and Streams Drill 1', 'boats, streams, upstream, downstream', 'Write downstream and upstream equations explicitly.

Keep the still-water and stream speeds as separate unknowns.', 'Use half-sum for still water and half-difference for stream speed.

After that, distance and time use the same speed-distance formula.', 60, 'easy'),
    (6, 'aptitude', 'Time and Work Drill 1', 'time and work, rates, combined efficiency', 'Convert each worker into one-day work before combining them.

Keep the total work as 1 unit unless the question needs a different base.', 'Do not add days directly; add rates.

After finding the combined rate, take the reciprocal to get time.', 60, 'easy'),
    (7, 'aptitude', 'Profit, Loss and Interest Drill 1', 'profit, loss, simple interest', 'Always compare gain or loss with cost price, not selling price.

Use the standard simple interest formula before substituting values.', 'Most mistakes come from using the wrong base for the percentage.

Interest questions reward clean substitution more than tricks.', 60, 'easy'),
    (8, 'aptitude', 'Mixed Quant Drill 1', 'percentages, ratio, speed, work, profit', 'Spend a few seconds deciding the concept before solving.

Do not jump into arithmetic until you know the formula family.', 'Mixed sets are about recognition and calm switching between concepts.

Keep a one-word label beside each question in your rough work.', 60, 'easy'),
    (9, 'aptitude', 'Advanced Percentages and Ratios Drill 1', 'successive change, ratios, markups', 'Pause before the first step and identify the base quantity.

