insert into public.task_questions (
  task_id,
  position,
  prompt_md,
  question_type,
  explanation_md,
  sample_answer_md,
  source_platform,
  source_url
)
select
  t.id,
  seed.position,
  seed.prompt_md,
  seed.question_type,
  seed.explanation_md,
  seed.sample_answer_md,
  seed.source_platform,
  seed.source_url
from public.tasks t
join public.plan_days pd on pd.id = t.plan_day_id
join public.plan_templates pt on pt.id = pd.plan_template_id
join (
  values
    (1, 1, 'What is 20% of 500?', 'mcq', '20% means 20/100. Multiply 500 by 20 and divide by 100.', '', null, null),
    (1, 2, 'A value rises from 300 to 390. What is the percentage increase?', 'mcq', 'Increase = 90. Percentage increase = increase / original x 100.', '', null, null),
    (1, 3, 'If 30% of a number is 104.4, what is the number?', 'mcq', 'Number = part / (30/100).', '', null, null),
    (1, 4, 'An item marked at 1400 is sold after a 15% discount. What is the selling price?', 'mcq', 'Selling price = marked price x (100 - discount) / 100.', '', null, null),
    (1, 5, 'After a 25% discount, an item sells for 525. What was the marked price?', 'mcq', 'Sale price = marked price x (100 - discount) / 100, so marked price = sale price / remaining fraction.', '', null, null),
    (1, 6, 'A price increases by 40% and then decreases by 25%. What is the net effect?', 'mcq', 'Use successive change: net % = a - b - ab/100.', '', null, null),
    (1, 7, 'What is 20% of 420?', 'mcq', '20% means 20/100. Multiply 420 by 20 and divide by 100.', '', null, null),
    (1, 8, 'A value rises from 220 to 264. What is the percentage increase?', 'mcq', 'Increase = 44. Percentage increase = increase / original x 100.', '', null, null),
