    (1, 10, 'An item marked at 560 is sold after a 10% discount. What is the selling price?', 'mcq', 'Selling price = marked price x (100 - discount) / 100.', '', null, null),
    (2, 1, 'A sum of 196 is divided in the ratio 3:4. What is the first share?', 'mcq', 'First share = total x first part / total parts.', '', null, null),
