    (2, 3, '4 notebooks cost 88. What will 10 notebooks cost at the same rate?', 'mcq', 'Use direct proportion: unit price x required quantity.', '', null, null),
    (2, 4, 'A sum of 110 is divided in the ratio 2:3. What is the first share?', 'mcq', 'First share = total x first part / total parts.', '', null, null),
    (2, 5, 'Simplify the ratio 28:40.', 'mcq', 'Divide both terms by their highest common factor.', '', null, null),
    (2, 6, '8 notebooks cost 160. What will 12 notebooks cost at the same rate?', 'mcq', 'Use direct proportion: unit price x required quantity.', '', null, null),
    (2, 7, 'A sum of 336 is divided in the ratio 5:7. What is the first share?', 'mcq', 'First share = total x first part / total parts.', '', null, null),
