    (2, 9, '6 notebooks cost 120. What will 8 notebooks cost at the same rate?', 'mcq', 'Use direct proportion: unit price x required quantity.', '', null, null),
    (2, 10, 'A sum of 100 is divided in the ratio 2:3. What is the first share?', 'mcq', 'First share = total x first part / total parts.', '', null, null),
    (3, 1, 'A vehicle covers 216 km in 4 hours. What is its speed?', 'mcq', 'Speed = distance / time.', '', null, null),
    (3, 2, 'A traveler covers equal distances at 36 km/h and 72 km/h. What is the average speed?', 'mcq', 'For equal distances, average speed = 2ab / (a + b).', '', null, null),
